INSERT INTO `commentairerp` (`id`, `commentaire1`, `commentaire2`, `commentaire3`, `NumDossierCre`) VALUES
(1, 'Na', 'Na', 'le levier financier ne respecte pas la norme car le client manque le liquidite due a une commande ', '15939'),
(2, 'Le client presente une capacite de paiement de 812 dollars.', 'Son bilan est plus constitue de ses avoirs vu la nature de l activite.', 'Le client percoit des loyers d ou la non cohenrence de certains ratios', '59686'),
(3, 'NA', 'NA', 'NA', '52533'),
(4, 'NA', 'NA', 'NA', '52652'),
(5, 'NA', 'Il y a une variation positive significative de la situation financiere de monsieur MUBEMBA POMPON ', 'L analyse qualitative a ete effectuee avec succes en respectant les regles de l art ', '61600'),
(6, 'Le client est à  son 3e cycle chez MICROPOP SA. Lors de son précèdent cycle, il a travaillÃ© avec zÃ©ro jour de retard, un comportement très appréciable. Actuellement, le client veut Ã  nouveau Ãªtre accompagner par l''institution pour un montant de 8000$ pour dÃ©douaner ses marchandises en provenance de DUBAI. Rappelons que nous avons constater une augmentation du chiffre d''affaire du business du client au prÃ¨s de 55%, mais aussi ses ventes moyennes. Ce qui lui permet d''augmenter aussi sa capacite de paiement Ã  plus de 68%, comparativement Ã  son cycle prÃ©cÃ©dent. \r\nNous avons calculÃ© le chiffre d''affaire du business du client sur base de la mÃ©thode max-min des ventes journaliÃ¨res de 7 derniers jours, ce qui nous a donnÃ© 36356$; Son CMV est de 25986$; Nous avons par aprÃ¨s dÃ©duit toutes les charges opérationnelles et prives, ce qui nous permis de degage une capacite de paiement de 5214$.', 'Le jour de l''analyse, nous avons trouver le client avec 750$ en main comme vente du jour; et avons considerer 800$ de la valeur des équipements et outils aprés l''amortissement; et ensuite nous avons egalement tenu compte de ses 2100$ de garantie qu''il posse¨de auprÃ¨s de son bailleur du local commercial. Ce qui nous a donnÃ© un capital propre de 56979$.', 'Sur la rotation du stock, ce ratio ne peut remplir la norme car Ã  priori, les activitÃ©s ou les piÃ¨ces de rechanges tourne un peu de maniÃ¨re lente, mais possÃ¨de une liquiditÃ© consÃ©quente pour couvrir le crÃ©dit.', '29320'),
(7, 'Le client possede une salle de fete. Apres deduction de toutes les charges, il presente une capacite de paiement de 898 dollars.', 'Le client  possede 200 chaises en plastique dont la valeur est estime a 800 dollars.', 'Le client est dans le service, il possede une salle de fete dâ??ou lâ??incoherence et le non respect de certains ratio.', '60198'),
(8, 'Nous avons obtenu le chiffre d''affaire du business de la cliente sur base des ventes de 3 derniers jours, qui fait un total de 5133$. Son CMV revient a 3583$; En deduisant ses depenses privees et operationnelles, nous obtenons une capacite de paiement de 900$.', 'Le jour de la visite, nous avons trouve la cliente avec zero dollars en main; le total de ses equiepements et outils font 1622$; son capital propre revient a 4629$.', 'Tous les ratios sont bons.', '16424'),
(9, 'Nous avons obtenu son CA sur base des ventes min-max du client; ce qui nous a donne un total de 6360$, en deduisant toutes les charges, nous obtenons une capacite de paiement de 2937$.', 'Le jour de la visite, nous avons trouver le client avec 0$, le total des equipements font 15400$.', 'Nous sommes face a une activite de service et certains ratios ne peuvent respecter les normes.', '45588'),
(10, 'le client est a son 2e cycle, il solicite un pret de 15000$; nous avons calcule son chiffre daffaire sur base des ventes journalieres min-max qui nous a donne un total de 8720$ et son coup de marchandise vendue a 4750$; en deduisant toutes les charges privees et operationnelles, nous degageaons une capacite de paiement de 3293$. ', 'Le jour de l''analyse, nous avons trouve le client avec 380$ en main.', 'Tous les ratios sont bons, a lexception de celui de la rotation de stock car nous sommes face a une activte ou les produits secoulent a pas de tortue.', '29972'),
(11, 'Nous avons calcule le chiffre daffaire du client sur base des ventes journalieres min-max, qui nous a degagÃ© un total de 26772$, son CMV a donne 14579$. En deduisant toutes les charges privees et operationnelles, sa capacite de paiement degagee est de 5137$.', 'Le jour de la visite, nous avons trouve le client avec 280$ en main, son stock evalue a hauteur de 119490$; son capital propre est de 98090$.', 'Dans ces genres dactivite, certains ratios ne peuvent respecter la norme car nous sommes face a une activite ou les marchandises secoulent pas assez rapidement et prenne un peu du temps avant un nouveau appro, cest par exemple la rotation de stock.', '93333'),
(13, 'Na', 'Na', 'Le ratio du levier financier ne respecte pas la norme pas la norme parceque le pret micropop doit etre inferieur a l actif circulant qui est compose generalement de la liquidite et du stock qui est faible parceque c est la location (le service) qui rapportent beaucoup et au moment des analyses l argent est remis au proprietaire le  matin apres inventaire', '88721'),
(14, 'NA', 'NA\r\n', 'Le ration d''endettement ne donne pas parce que ce dernier se calcul avec le montant proposé par l''agent de crédit et non avec le montant proposé par le comité', '55237'),
(16, 'Na', 'Na', 'Le ratio du levier financier et de la liquidité ne correspondent pas à la norme parceque le capital propre du client et son  actif circulant sont inférieur au prêt workflow. C''est ça même la raison de la demande de la cliente pour augmenter son capital propre et son fond de roulement', '20414'),
(17, 'NA', 'NA', 'Le ratio de rotation de stock ne tient pas parce que le stock de la cliente ne s''épuise pas totalement avant de passer une autre commande.', '27427'),
(18, 'NA', '', 'Étant donné que l''activité est un service les différents rations suivants ne vont pas respecter la règle de l''art - ratio d''endettement  - ration de liquidité et - Le levier financier', '71410'),
(19, 'Le client est a son 2e cycle chez Micropop sa, lors de son cycle precedent, il a travaille avec zero jour de retard pour un credit de 9900$ pour 12 mois. Actuellement, le client sollicite un credit de 25000$ pour 12 mois en vu de faire recourt aux quelsques articles importants qui sont en diminution de son stock. De ce fait, nous avons calcule son chiffre d affaire sur base de la methode min-max, qui nous a donne 25820$; en faisant la deduction du cout marchandise 8135$, des depenses operationnelles 4999$, des depenses privees 1579$, nous arrivons a trouver une capacite de paiement de 11106$. Ce qui couvrirait entierement son credit pour chaque mensualite.', 'Lors de l analyse, nous avons trouve le client avec 1100$ de la vente du jour, son stock est evalue a hauteur de 345000$, ce qui nous donne un total de 346100$ des actifs circulants; les immobilises font un totaux de 3950$, en raison de 950$ pour les equipements et outils et 3000$ pour le vehicule. Le capital propre est ainsi degager pour un total de 350050$.', 'Tous les indicateurs sont corrects, a l exception de la rotation de stock compte tenu de la nature de l activite car le client s approvisionne trimestriellement l annee, ce qui donne une rotation de stock lente, mais l activite est entierement rentable et liquide capable de couvrir sont credit. Nous avons egalement considerer 20% du stock de l activite du client car les articles vendus ne sont pas perissable et par consequent, nous les prenons enguise de garantie, hormis le vehicule mis en gage pour couvrir le ratio de garantie. Le client est de bonne moralite, et nous compte sur l institurion MICROPOP SA pour pouvoir l accompagner de nouveau mais aussi pour fideliser notre clientele.', '74865'),
(20, 'La cliente est a son 3 e cycle chez MICROPOP SA, lors de 2 derniers cycles, elle a marche avec zero jours de retard, un comportement appreciable et encourageante; elle avait obtenu 6500$ pour soon cycle passe, actuellement, elle solicite 15000$ pour renforcer son stock car elle possede une clientele remarquable dans le coin. Nous avons calcule son chiffre d affaire sur base de la methode de 3 derniers jours, ce qui nous a donne un total de 55432$; en deduisant le cout de marchandise 43337$; les depenses operationnelles 3037$, les depenses privees 1573$, nous arrivons a degager une capacite de paiement de 7484$. Avec cette capacite, la cliente serait entierement en mesure de couvrir son credit comme lors de deux derniers cycles.', '', 'Tous les indicateurs sont bons, a l exception de la rotation de stock qui tourne un peu lentement compte tenu de l activite du client qui n achete pas tous les jours comme dans d autres activites d ou cette remarque; mais son activite est entierement liquide et possede la capacite de couvrir son credit. Nous avons egalement tenu compte de 20% de son stock pour couvrir la garantie etant donne que la client ne possede pas vraiment de garantie telle que vehicule ou parcelle, mais elle a un comportement irreprochable vis a vis de ses engagements envers MICROPOP SA; nous avons tenu compte de ce 20% comme le veut la procedure mais aussi car c est une bonne cliente que nous comptons l accompagner dans son besoin a fon de roulement mais aussi la fideliser dans notre institution. ', '77990'),
(21, 'On a considéré le trois derniers mois pour trouver le  chiffre d''affaires', '', 'Commentaire pour ratio Certain ratio ne correspond pas, parceque l''activité du client est un service donc y''a pas des stocks', '31980'),
(22, 'NA', 'NA', 'NA', '29028'),
(23, 'Nous avons calcule le chiffre d affaire de l activite sur base des ventes de 3 derniers jours, ce qui nous a donne un total de 26133$; en faisant la deduction du cout de marchandise vendue 15288$; de ses depenses operationnelles 1728$; de ses depenses privees 1120$; nous arrivons a degager une capacite de paiement de 7997$.', 'Le jour de l analyse, la cliente nous a presenter 300$ comme caisse a la maison, pour le compte de la vente de la journee precedente apres avoir effectuer quelques depenses familiale, son stock a ete evaluer a hauteur de 40812$; elle possede une garantie commerciale de 900$; d ou son capital propre est de 42012$.', 'Tous les indicateurs sont bons a l exception de la rotation de stock car la cliente se trouve dans la vente des articles de la quincaillerie, d ou ca peut prendre quelques temps pour tout ecouler et s approvisionner de nouveau. Mais l activite possede entierement la capacite de couvrir le credit.', '09804'),
(24, '', 'Le jour de l analyse, nous avons trouve le client avec 580$ en main comme vente du jour, son stock est evalue a hauteur de 314850$, son capital propre est de 315430$.', '', '03948'),
(25, 'les couts des marchandises vendues sont faibles car le client vend en detail donc y''a plus d''interet', 'le client reside et exerce ses activites dans la parcelle familiale ', 'le ratio de stock ne donne pas car le client venait acheter un lot des medicaments ', '41770'),
(26, 'NA', 'NA', 'NA', '97442'),
(27, '', '', 'Étant donné que l''activité est un service : le ratio de liquidité, le ratio d''endettement, le levier financier, ainsi que la rotation de stock ne vont pas respecter la règle de l''art, car il n''y a ni le stock, ni actif circulant.', '08487'),
(28, 'Nous avons calcule le chiffre d affaire de l activite du client sur base de la methode min-max des ventes journalieres, ce qui nous a donne un total de 28600$; nous avons par la suite deduit son cout de marchandise vendue de 10414$, ses depenses operationnelles de 7049$; ses depenses privees de 1540$, ce qui nous a degager une capacite de paiement de 9596$.', 'Le jour de la visite, nous avons trouve le client avec zero dollars en main car il venait d effectuer quelques depenses familiales, son stock a ete evaluer a hauteur de 118835$; ses equipements a 700$, en faisant la deduction  des passifs, nous degageons un capital propre de 99535$.', 'Tous les indicateurs sont corrects, a l exception de la rotation de stock compte tenu de la nature de l activite du client qui vend des pieces de rechanges et d ou on cycle d exploitation s effectue que 2 fois l annee en tenant compte des ventes et commandes de la clientele, mais aussi du temps que la marchandise arrive au pays.', '21247'),
(30, 'NA', 'le solde en banque est la somme des ivoires à la TMB et chez MICROPOP SA à la date de l''analyse.', ' 1. La cliente possède une faible garantie mais dispose de suffisamment de revenus pour rembourser son crédit. 2. La rotation de Stock,  l''activité étant un Salon de coiffure (service), les différents produits vendus ne sont pas des produits à consommation récurrente d''où le non respect de la norme.', '94912'),
(31, 'Nous avons obtenu le chiffre d affaire de l activite sur base des journalieres de 3 derniers jours declare par le client, ce qui a donne un total de 78800$, nous avons ensuite deduit le cout de marchandise vendue de 65305$; les depenses operationnelles de 4461$; les depenses privees de 730$, ce qui nous a donne une capacite de paiement de 8303$.', 'Nous avons trouve le client en main avec 8850$ comme ventes du jour ainsi que l argent destine a la commande du jour, son stock activite et depot a ete evalue a 85227$, le client possedeun vehicule sprinter qu il met en gage dont la valeur est estime a 7000$. Son capital propre degage est 101077$.', 'Tous les ratios sont corrects a l exception de la rotation de stock compte tenu de genre d activite ou les articles s ecoulent mais pas a une rotation grande.', '70099'),
(32, 'Nous avons calcule le chiffre d afaire du client sur base des ventes journalieres max-min de 6 derniers jours, ce qui nous a donne un total de 6400$, nous avons ensuite deduit son cout de marchandise vendues de 4101$; ses depenses operationnelles de 130$; ses depenses privees de 830$; en ajoutant ses revenus locatifs de 350$; nous avons degage une capacite de paiement de 1688$.', 'Nous aons evalue le stock de la cliente a hauteur de 2167$; ses equipements et outils font un total 1340$, son capital propre est de 3507$.', 'Tous les indicateurs sont corrects a l exception de levier financier car la cliente ne possede pas assez des actifs circulants le jour de la visite, tout comme son stock, ce qui ne respectera pas la norme, tout comme le ratio d endettement ou l on voit que le capital propre de la client est nettement inferieur au pret micropop, mais l activite semble financable car elle repond a la liquidite necessaire et une capacite eleve pour couvrir mensuellement le credit.', '32961'),
(33, 'NA', 'LE 480$ C''EST LA GARANTIE DU LOYER BUSINESS DU CLIENT ', 'LE RATIO ROTATION DE STOCK N''A PAS TENU CAR LA FREQUENCE D''ACHAT EST FAIBLE ', '69630'),
(34, 'Na', 'Na', 'L''actif circulant n''est pas considerable, c''est pourquoi le ratio du levier financier et celui d''endettement ne respectent pas la norme. La cliente a besoin d''un coup de pousse pour booster ses activités', '39620'),
(35, '', '', 'Le ratio de stock n''a pas tenu vu que le client venait d''acheternune grande quantité des marchandises à la veille de l''analyse', '32679'),
(36, 'NA', 'NA', 'le ratio d’endettement ne correspond à cause de la dernière mensualité du credit de vision fund qui va prendre fin au mois d’août,', '44420'),
(37, 'Nous avons calcule le chiffre d affaire de l activite du client sur base de l approche max-min, ce qui nous a donne un total de 41548$, en deduisant le cout des marchandises vendues 19323$, les depenses operationnlles 12536$, les depenses privees 1930$, nous degageons une capacite de paiement de 7758$.', 'Le jour de l analyse, nous avons trouve le client avec 1850$ en cash, son stock fait 123200$, le total des circulants 125050$, le total des actifs 129850$, le capital propre est de 89688$.', 'Tous les indicateurs sont bons, a l exception de la rotation de stock compte tenu du cycle d exploitation du client et de la nature d activite, ce qui parrait normal  que ce ratio ne respecte pas la norme. Mais l activite est rentable et entierement financable. ', '20749'),
(38, 'NA', 'NA', 'NA', '48342'),
(39, 'Au vu des activités, la cliente présente une capacité de paiement de 1400 dollars environs.', 'La cliente possède un bar et vends également des produits alimentaires qu''elle livre au super marché food Market. L''analyse a été faite sur base de la terrasse et ses livraisons ont été considéré comme autre source de revenu. Elle vend exclusivement les produits de BRACONGO.', 'NA', '64686'),
(40, 'Le client est a son 3e cycle chez MICROPOP SA, nous avons calcule son chiffre d affaire sur base des ventes de ces 3 derniers jours, ce qui nous a degage un total de 14400$; son cout de marchandise vendue nous a donne 11318$. En deduisant ce dernier, ainsi que les depenses privees et operationnelles, nous avons trouve une capacite de paiement de 1968$.', 'Le jour de l analyse, nous avons trouve le client en main avec 850$, son stock activite et chambre a ete evalue a 5722$; les equipements outils font un total de 600$; ce qui nous donne un capital propre de 7172$.', 'Tous les ratios sont corrects, a l exception de celui de la garantie, qui donne 50 pourcent, et nous demandons une exception pour ce ratio afin que le client soit servi au montant propose au comite car son activite est entierement rentable.', '31705'),
(41, 'Le client presente une capacité de paiement de 7346 dollars et peut facilement payer son crédit.', 'Les meubles ainsi que les équipements sont des montants estimatifs à la valeur nette des biens du client. ', 'Le client oeuvre principalement dans le service qui est la principale source de revenu.', '95869'),
(42, 'Nous avons pris en compte les ventes de trois derniers jours.', 'Les actifs de la cliente couvre le montant du prêt solliciter.', 'Les ratios sont conformes à la norme.', '40571'),
(43, 'Nous avons trouve son chiffre d affaire sur base des methodes de 3 derniers jours ce qui donne 13260$. Apres deduction de toutes les charges, la capacite de paiement trouve est de 1296$.', 'Nous avons trouvé la cliente en main avec 550$. Son stock est evaluer a hauteur de 4633$. Ses equipements font 1000$ apres amortissement. Son capital propre est de  6183$.', 'Tous les ratios sont corrects.', '94332'),
(44, 'Nous avons insere le montant du chiffre du client qui est 400$ de son revenu locatif mensuel, nous avons egalement tenu compte de son salaire, ce qui nous a donne une capacite de paiement de 1823$.', 'Nous avons evalue la parcelle du client a hauteur de 80000$ que nous avions insere dans la rubrique, local commercial comme actif immobilise du client. En tenant compte de la garantie locative percue de 2000$, Nous avons trouve un capital propre de 78000$.', 'Certains ratios ne respectent pas la norme car l actvite est encours d etre termine, le client compte avoir un pret pour terminer avec quelques travaux de son immeuble R+1 situe sur Bobozo 137 dans la commune de  LIMETE.', '40950'),
(45, 'La cliente est dans la vente de la friperie et les articles de la couture.', 'La cliente une chiffre d''affaire importante et elle maîtrise bien son activité.', 'Ras', '20845'),
(46, 'Ras', 'Ras', 'Ras', '38967'),
(47, 'Na', 'Na', 'Le ratio de rotation de stock ne correspond pas à la norme parceque l''activité est une imprimerie et il n y a pas de coût de marchandise vendues (CMV)\r\n Le ratio de liquidité et du levier financier ne respectentvpas aussi la norme, parceque le client n''a pas une somme considerable en caisse ou en banque pour couvrir les actifs circulant, il investie son argent dans d''autres activités entre autre l''achat et la vente des terrains', '19665'),
(48, 'La cliente présente une capacité de 2732 dollars, elle peut donc payer les deux crédits.', 'Dans les actifs sont inclus les garanties locatifs et les équipements ( bancs)', 'La cliente possède une école, il s’agit donc d’un service', '61249'),
(49, 'NA', 'NA', 'Le ratio de liquidité, Levier financier ainsi que le ratio d''endettement ne respectent pas car l''activité du client c''est la production', '20210'),
(50, 'Na', 'Na', 'Le ratio d''endettement ne respecte pas la norme parceque la majorité du capital propre de la cliente est basé dans son stock, mais celle ci ne se retrouve pas automatiquement dans le bilan', '35970'),
(51, 'NA', 'NA', 'NA', '72155'),
(52, 'le client présente une capacité de paiement de 1163 dollars.', 'lors de la visite, le client n''avait pas encore vendu vu la nature de l''activité et il venait de s''approvisionner, d''où l''absence de liquidité.', 'le ratio d''endettement n''est pas conforme à la norme car son actif circulant est constitué du stock disponible, le client ne disposant pas d''épargne. La visite s''était faite en début de journée.', '96561'),
(53, 'NA', 'NA', 'LE RATIO DE LIQUIDITE,LEVIER FINANCIER,RATIO D''ENDETTEMENT ,RATIO ROTATIO DE STOCK N''A PAS RESPECTE CAR L''ACTIVITE C''EST UN SERVICE', '31253'),
(54, 'NA', 'NA', 'NA', '17611'),
(55, 'Le client dispose d''une capacité de paiement de 2443 dollars. Il vend également des véhicules et a déclaré disposé d''un revenu net mensuel de 2000 dollars en moyenne.', 'L''analyse a été faite sur base de la vente de pièces rechanges, son actif circulant est constitué du stock ainsi de la vente du jour que nous avons trouvé lors de l''analyse.', 'L''activité analyse est la vente de pièces de rechange, le client peut facilement payer son crédit mais ne dispose pas d''assez de garantie. Son actif circulant est constitué de son stock. ', '74800'),
(56, 'Nous avons calcule le chiffre d affaire de la cliente sur base de la vente de 3 derniers jours ce qui nous a fourni un total de 8400$. Nous avons en suite deduit le cout de marchandise vendue de 5758$, les depenses operationnelles de 601$, les depenses privees de 503$ ce qui nous a degage une capacite de paiement de 1537$\r\n', 'Nous avons trouve la cliente en mains avec 1290$ pour ces dernieres ventes destinees a la commande des marchandises ainsi que la vente du jour. L evaluation de son stock nous a donne un total de 1714$ ce qui nous donne un total des actifs circulants de 3004$. Du cote des immobilises ses equipements font un total de 500$, elle possede une garantie de 1400$ ce qui nous fait un total de 1900$ des actifs immobilises. Son capital propre trouve est de 4904$. \r\n\r\n\r\n ', 'Tous les ratios sont corrects.', '88366'),
(57, 'Le client montre une bonne maîtrise de son activité, avec un emplacement stratégique attirant une large clientèle. ', 'les actifs du client sont principalement liquides et rapidement mobilisables, ce qui constitue une force pour son activité.', 'NA', '29645'),
(58, 'NA', 'NA', 'NA', '42012'),
(59, 'La cliente montre une bonne maîtrise de son activité, avec un emplacement stratégique attirant une large clientèle', 'les actifs de la cliente sont congélateurs et son stocks', 'ratio de liquidité: après les analyse faites, la cliente présente une capacité de payer sa dette', '57148'),
(60, 'NA', 'NA', 'Les ratios de liquidité et financier ne donnent pas parce que nous avions analyses les recettes perçu d''une salle polyvalente funaire et de fête.', '25869'),
(61, 'Nous avons calcule le chiffre d affaire de l activite du client sur base de la methode max-min de 7 derniers jours des ventes, et avons trouve un total de 13120$. En deduisant son cout de marchandise vendue de 9974$; ses depenses operationnelles de 454$; ses depenses privees de 955$; nous degageons une capacite de paiement de 1736$.', 'Nous avons trouve le client avec 970$ en main le jour de la visite en raison de vente du jour ainsi qu une partie destinee a la commande des marchandises, son stock a ete evalue a hauteur de 918$, ses outils apres amortissement font 1200$. Ce qui nous donne un capital propre de 3088$.', 'Tous les ratios sont corrects.', '81543'),
(62, 'La cliente présente une capacité de paiement de 1448 dollars. Elle peut facilement payer son crédit et continuer son activité.', 'La cliente a un faible stock vu qu''elle  était en attente de livraison lors de l''analyse. ', 'La cliente présente un actif circulant faible suite au stock d''où l''objet du crédit augmenté le stock. ', '11771'),
